1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	  material?: string;
6	}
7	
8	interface QuoteStep {
9	  items: Item[];
10	}
11	
12	interface Customer {
13	  yearsWithMHPCO: number;
14	}
15	
16	const PROCESSING_FEE = 5;
17	const FIRST_INSURANCE_SURCHARGE = 0.1;
18	const CURSE_SURCHARGE = 0.5;
19	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
20	const HIGH_ENCHANTMENT_THRESHOLD = 5;
21	const LOYALTY_DISCOUNT = 0.2;
22	const LOYALTY_THRESHOLD_YEARS = 2;
23	const FOLLOWUP_DISCOUNT = 0.15;
24	
25	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
26	  sword: 100,
27	  amulet: 60,
28	  staff: 80,
29	  potion: 40,
30	};
31	
32	const COMPONENT_TYPES = ["rune", "moonstone"];
33	const COMPONENT_PREMIUM = 25;
34	const BLOCK_SIZE = 3;
35	const BLOCK_PREMIUM = 60;
36	
37	// Sum `valueOf` applied to each element of an iterable.
38	const sumOf = <T>(values: Iterable<T>, valueOf: (value: T) => number): number => {
39	  let sum = 0;
40	  for (const value of values) sum += valueOf(value);
41	  return sum;
42	};
43	
44	const isComponent = (item: Item): boolean =>
45	  COMPONENT_TYPES.includes(item.type);
46	
47	const isMainItem = (item: Item): boolean => !isComponent(item);
48	
49	// A type is known if it is a priced main item or a recognised component.
50	const isKnownItemType = (type: string): boolean =>
51	  type in BASE_PREMIUM_BY_TYPE || COMPONENT_TYPES.includes(type);
52	
53	const rejectUnknownItemType = (items: Item[]): void => {
54	  const unknown = items.find((item) => !isKnownItemType(item.type));
55	  if (unknown) {
56	    throw new Error(`Unknown item type: ${unknown.type}`);
57	  }
58	};
59	
60	// A group of exactly BLOCK_SIZE alike components is priced at the discounted
61	// BLOCK_PREMIUM; any other count is priced per component.
62	const componentGroupBasePremium = (count: number): number =>
63	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
64	
65	// An item-specific surcharge adds `rate` of the item's base premium when its
66	// condition holds, and nothing otherwise.
67	const surchargeWhen = (item: Item, applies: boolean, rate: number): number =>
68	  applies ? rate * basePremiumForItem(item) : 0;
69	
70	// Cursed items add a surcharge equal to CURSE_SURCHARGE of their base premium.
71	const curseSurcharge = (item: Item): number =>
72	  surchargeWhen(item, item.cursed ?? false, CURSE_SURCHARGE);
73	
74	// Highly enchanted items (enchantment at or above the threshold) add a
75	// surcharge equal to HIGH_ENCHANTMENT_SURCHARGE of their base premium.
76	const highEnchantmentSurcharge = (item: Item): number =>
77	  surchargeWhen(
78	    item,
79	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
80	    HIGH_ENCHANTMENT_SURCHARGE,
81	  );
82	
83	// Collapse floating-point artifacts (e.g. 197.49999999) before rounding, so we
84	// never round a value that is only spuriously above or below a whole number.
85	const collapseFloatArtifacts = (amount: number): number =>
86	  Number(amount.toFixed(6));
87	
88	// Premiums are rounded UP, in MHPCO's favor.
89	const roundUpInMHPCOsFavor = (amount: number): number =>
90	  Math.ceil(collapseFloatArtifacts(amount));
91	
92	// Payouts are rounded DOWN, in MHPCO's favor.
93	const roundDownInMHPCOsFavor = (amount: number): number =>
94	  Math.floor(collapseFloatArtifacts(amount));
95	
96	// Look up a per-type value, treating an unknown type as contributing nothing.
97	const valueByType = (table: Record<string, number>, type: string): number =>
98	  table[type] ?? 0;
99	
100	const basePremiumForItem = (item: Item): number =>
101	  valueByType(BASE_PREMIUM_BY_TYPE, item.type);
102	
103	// Each main item is priced on its own.
104	const mainItemsBasePremium = (items: Item[]): number =>
105	  sumOf(items, basePremiumForItem);
106	
107	// Tally how many values fall under each key, where the key is read off each
108	// value by `keyOf`.
109	const countBy = <T>(values: Iterable<T>, keyOf: (value: T) => string): Map<string, number> => {
110	  const counts = new Map<string, number>();
111	  for (const value of values) {
112	    const key = keyOf(value);
113	    counts.set(key, (counts.get(key) ?? 0) + 1);
114	  }
115	  return counts;
116	};
117	
118	const countByType = (items: Item[]): Map<string, number> =>
119	  countBy(items, (item) => item.type);
120	
121	// Components are grouped by type, and each group is block-priced.
122	const componentsBasePremium = (components: Item[]): number =>
123	  sumOf(countByType(components).values(), componentGroupBasePremium);
124	
125	const policyBasePremium = (items: Item[]): number =>
126	  mainItemsBasePremium(items.filter(isMainItem)) +
127	  componentsBasePremium(items.filter(isComponent));
128	
129	// Tier 1 — item-specific surcharges: computed off each affected item's base
130	// premium and summed across the policy. (e.g. curse; later high-enchantment.)
131	const itemSurcharges = (items: Item[]): number =>
132	  sumOf(items, (item) => curseSurcharge(item) + highEnchantmentSurcharge(item));
133	
134	// A policy-wide modifier adds `rate` of the policy base premium when its
135	// condition holds, and nothing otherwise.
136	const fractionOfPolicyBaseWhen = (
137	  policyBase: number,
138	  applies: boolean,
139	  rate: number,
140	): number => (applies ? rate * policyBase : 0);
141	
142	// Every new policy carries a surcharge equal to FIRST_INSURANCE_SURCHARGE of
143	// the policy base premium. It always applies, so it is computed directly
144	// rather than going through the conditional fractionOfPolicyBaseWhen helper.
145	const firstInsuranceSurcharge = (policyBase: number): number =>
146	  FIRST_INSURANCE_SURCHARGE * policyBase;
147	
148	// Long-standing customers (at or above the loyalty threshold) receive a
149	// discount equal to LOYALTY_DISCOUNT of the policy base premium.
150	const loyaltyDiscount = (policyBase: number, customer: Customer): number =>
151	  fractionOfPolicyBaseWhen(
152	    policyBase,
153	    customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS,
154	    LOYALTY_DISCOUNT,
155	  );
156	
157	// Every contract after the customer's first (a non-zero quote index) receives a
158	// discount equal to FOLLOWUP_DISCOUNT of the policy base premium.
159	const followUpDiscount = (policyBase: number, quoteIndex: number): number =>
160	  fractionOfPolicyBaseWhen(policyBase, quoteIndex >= 1, FOLLOWUP_DISCOUNT);
161	
162	// Tier 2 — policy-wide modifiers: each computed as a fraction of the policy
163	// base premium. Surcharges add; discounts subtract. (first-insurance surcharge,
164	// loyalty discount, follow-up discount.)
165	const policyWideModifiers = (
166	  policyBase: number,
167	  customer: Customer,
168	  quoteIndex: number,
169	): number =>
170	  firstInsuranceSurcharge(policyBase) -
171	  loyaltyDiscount(policyBase, customer) -
172	  followUpDiscount(policyBase, quoteIndex);
173	
174	export const quote = (
175	  customer: Customer,
176	  step: QuoteStep,
177	  quoteIndex: number,
178	): number => {
179	  rejectUnknownItemType(step.items);
180	
181	  const policyBase = policyBasePremium(step.items);
182	
183	  const total =
184	    policyBase +
185	    itemSurcharges(step.items) +
186	    policyWideModifiers(policyBase, customer, quoteIndex) +
187	    PROCESSING_FEE;
188	  return roundUpInMHPCOsFavor(total);
189	};
190	
191	interface Damage {
192	  itemType: string;
193	  amount: number;
194	}
195	
196	interface Incident {
197	  cause: string;
198	  damages: Damage[];
199	}
200	
201	interface ClaimResult {
202	  payout: number;
203	  remainingCap: number;
204	}
205	
206	const DEDUCTIBLE = 100;
207	const ENCHANTMENT_HALF_THRESHOLD = 8;
208	const HALF_REIMBURSEMENT = 0.5;
209	const CAP_MULTIPLIER = 2;
210	const COMPONENT_INSURANCE_VALUE = 250;
211	
212	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
213	  sword: 1000,
214	  amulet: 600,
215	  staff: 800,
216	  potion: 400,
217	};
218	
219	// Each item is insured for a fixed value; components share a flat value.
220	const insuranceValueForItem = (item: Item): number =>
221	  isComponent(item)
222	    ? COMPONENT_INSURANCE_VALUE
223	    : valueByType(INSURANCE_VALUE_BY_TYPE, item.type);
224	
225	const insuranceSum = (items: Item[]): number =>
226	  sumOf(items, insuranceValueForItem);
227	
228	// A policy's total payout cap is a fixed multiple of the insured value of its
229	// items. Premium-side modifiers (block discounts, surcharges) do not affect it.
230	const payoutCap = (policyItems: Item[]): number =>
231	  CAP_MULTIPLIER * insuranceSum(policyItems);
232	
233	// Items at or above the half-reimbursement enchantment threshold are reimbursed
234	// at only half the damage amount.
235	const isHalfReimbursed = (item: Item | undefined): boolean =>
236	  (item?.enchantment ?? 0) >= ENCHANTMENT_HALF_THRESHOLD;
237	
238	// What MHPCO reimburses for a single damage, before the deductible.
239	// Reimbursement turns solely on enchantment: high-enchantment items
240	// (at or above the threshold) get half the damage amount; everything else
241	// gets the full amount. Material is not inspected — dragon material is
242	// fully reimbursed simply because it falls in the full-amount branch, and
243	// half-reimbursement still wins for a high-enchantment dragon item.
244	const reimbursedAmount = (item: Item | undefined, amount: number): number =>
245	  isHalfReimbursed(item) ? HALF_REIMBURSEMENT * amount : amount;
246	
247	// A damage is reimbursed against the first policy item of its type.
248	const itemForDamage = (policyItems: Item[], damage: Damage): Item | undefined =>
249	  policyItems.find((item) => item.type === damage.itemType);
250	
251	// The net payout for a single damage: what MHPCO reimburses for the damaged
252	// item, less the per-damage deductible.
253	const netPayoutForDamage = (policyItems: Item[], damage: Damage): number =>
254	  reimbursedAmount(itemForDamage(policyItems, damage), damage.amount) -
255	  DEDUCTIBLE;
256	
257	// A claim is rejected if it reports more damages of a given type than the
258	// policy actually covers. This also rejects damage to an item type absent
259	// from the policy: its insured count is 0, so any such damage over-claims.
260	const rejectIfOverClaimed = (policyItems: Item[], incident: Incident): void => {
261	  const insuredCounts = countByType(policyItems);
262	  const damageCounts = countBy(incident.damages, (damage) => damage.itemType);
263	  for (const [type, count] of damageCounts) {
264	    if (count > (insuredCounts.get(type) ?? 0)) {
265	      throw new Error(`Claim rejected: more ${type} damages than insured`);
266	    }
267	  }
268	};
269	
270	// A claim is rejected if any damage reports a negative amount.
271	const rejectIfNegativeDamage = (incident: Incident): void => {
272	  if (incident.damages.some((damage) => damage.amount < 0)) {
273	    throw new Error("Claim rejected: negative damage amount");
274	  }
275	};
276	
277	export const claim = (
278	  policyItems: Item[],
279	  incident: Incident,
280	  startingRemainingCap: number = payoutCap(policyItems),
281	): ClaimResult => {
282	  rejectIfOverClaimed(policyItems, incident);
283	  rejectIfNegativeDamage(incident);
284	
285	  const rawPayout = sumOf(incident.damages, (damage) =>
286	    netPayoutForDamage(policyItems, damage),
287	  );
288	  // The payout is capped at whatever remains of the policy's payout cap.
289	  const payout = roundDownInMHPCOsFavor(
290	    Math.min(rawPayout, startingRemainingCap),
291	  );
292	  return { payout, remainingCap: startingRemainingCap - payout };
293	};
